93	<script type="text/javascript">
94	    let datagrid;
95	    let grid_data = [];
96	    let maxPage, nowPage, pageSize;
97	
98	    $(document).ready(function() {
99	        // from/to 날짜 최대값: 오늘 기준 3일 전 (그 이후 날짜는 선택 불가)
100	        const maxDate = new Date();
101	        maxDate.setDate(maxDate.getDate() - 3);
102	        const maxDateStr = maxDate.toISOString().split('T')[0];
103	        document.getElementById("cFrmDate").max = maxDateStr;
104	        document.getElementById("cToDate").max = maxDateStr;
105	
106	        // 직접 입력 또는 달력 선택 시 max 초과 차단
107	        $("#cFrmDate, #cToDate").on("change", function() {
108	            if ($(this).val() > maxDateStr) {
109	                alert("파일 복원은 오늘 기준 3일 이상 지난 신고일만 선택 가능합니다.");
110	                $(this).val(maxDateStr);
111	            }
112	        });
113	
114	        // 초기 데이터 로드
115	        ajaxData(1);
116	
117	        // 조회 버튼 이벤트
118	        $("#searchBtn").click(function() { ajaxData(1); });
119	
120	        // 엔터키 조회
121	        $("#sttemntNoSrchBody").keydown(function(e) { if(e.keyCode == 13) ajaxData(1); });
122	
123	        // 일괄 복원 버튼 이벤트
124	        $("#bulkRestoreBtn").click(function() {
125	            bulkRestore();
126	        });
127	
128	        // 전체 복원 버튼 이벤트
129	        $("#allRestoreBtn").click(function() {
130	            allRestore();
131	        });
132	    });
133	
134	    const __createElements = () => {
135	        let size = "width:100%; height:651px;";
136	        let heightSize = "height:" + ((30 * grid_data.length) + 51) + "px;";
137	        if(grid_data.length < 20) size = "width:100%;" + heightSize;
138	
139	        if (SBGrid.getGrid('datagrid')) datagrid.destroy();
140	
141	        let GridInitInfo = {
142	            "strParentId"           : "sbGridArea"
143	            , "strId"               : "datagrid"
144	            , "strCaption"          : "순번^선택^신고번호^제목^신고일^전체 파일"
145	            , "strColWidth"         : "5%,5%,13%,52%,17%,8%"
146	            , "strJsonRef"          : "grid_data"
147	            , "strStyle"            : size
148	            , "strDataHeight"       : "30"
149	            , "strToolTip"          : "true"
150	            , "bAllowUserResize"    : true
151	            , "strSelectMode"       : "free"
152	            , "strEmptyRecords"     : "검색결과가 없습니다."
153	            , "strOverflow"         : "hidden"
154	            , "strExplorerbar"      : "vertical"
155	            , "bIsFitWidth"         : true
156	        };
157	        let SBGridColumnInitInfo = [
158	            { "id" : "col0" , "type" : "output"   , "ref" : "rowNum"      , "style" : "text-align:center" }
159	            , { "id" : "col1" , "type" : "checkbox" , "ref" : "check"       , "style" : "text-align:center" }
160	            , { "id" : "col2" , "type" : "output"   , "ref" : "sttemntNo"   , "style" : "text-align:center" }
161	            , { "id" : "col3" , "type" : "output"   , "ref" : "cATitle"     , "style" : "text-align:left" }
162	            , { "id" : "col4" , "type" : "output"   , "ref" : "cDate"       , "style" : "text-align:center" }
163	            , { "id" : "col5" , "type" : "output"   , "ref" : "fileCnt"     , "style" : "text-align:center" }
164	            , { "id" : "col6" , "type" : "output"   , "ref" : "cNo"         , "bIsColHidden" : true }
165	        ];
166	        datagrid = createSBDataGrid(GridInitInfo);
167	        datagrid.createColumns(SBGridColumnInitInfo);
168	        datagrid.addEventListener("onclick", "fnRowClick", "", "");
169	    }
170	
171	    const ajaxData = (newPage) => {
172	        let data = {
173	            "newPage": newPage,
174	            "cFrmDate": $("#cFrmDate").val(),
175	            "cToDate": $("#cToDate").val(),
176	            "sttemntNo": $("#sttemntNoSrchHead").val() + "-" + $("#sttemntNoSrchBody").val()
177	        };
178	        $.ajax({
179	            url : "<c:url value='/fileRestore/selectRestoreSingoList.json'/>",
180	            type : 'post', data : data, dataType : 'json',
181	            success : function(json) {
182	                grid_data = json.resultList;
183	                for(let i=0; i<grid_data.length; i++) {
184	                    grid_data[i].check = false;
185	                    grid_data[i].rowNum = (json.newPage - 1) * json.pageSize + i + 1;
186	                }
187	                $("#totalCnt").text(json.maxPage);
188	                $("#totalFileCnt").text(json.totalFileCnt);
189	                __createElements();
190	                maxPage = json.maxPage; nowPage = json.newPage; pageSize = json.pageSize;
191	                $('#shim').smartpaginator({ totalrecords: maxPage, recordsperpage: pageSize, initval: nowPage, onchange: ajaxData });
192	            }
193	        });
194	    }
195	
196	    function bulkRestore() {
197	        let selectedSingoNos = [];
198	        for(let i=1; i<=grid_data.length; i++) {
199	            if(datagrid.getTextMatrix(i, 1) == "true" || datagrid.getTextMatrix(i, 1) == "1") {
200	                selectedSingoNos.push(datagrid.getTextMatrix(i, 6));
201	            }
202	        }
203	
204	        if(selectedSingoNos.length === 0) {
205	            alert("복원할 신고 건을 선택해 주세요.");
206	            return;
207	        }
208	
209	        if(confirm("선택한 " + selectedSingoNos.length + "건에 대해 일괄 복원을 요청하시겠습니까?")) {
210	            $.ajax({
211	                url: "<c:url value='/fileRestore/updateBulkFileRestore.do'/>",
212	                type: 'post',
213	                data: { singoNos: selectedSingoNos },
214	                dataType: 'json',
215	                success: function(res) {
216	                    alert(res.message);
217	                    ajaxData(nowPage);
218	                },
219	                error: function() {
220	                    alert("서버 통신 중 오류가 발생했습니다.");
221	                }
222	            });
223	        }
224	    }
225	
226	    function allRestore() {
227	        if(grid_data.length === 0) {
228	            alert("조회된 결과가 없습니다.");
229	            return;
230	        }
231	
232	        if(confirm("현재 검색 결과 전체(" + maxPage + "건)에 대해 복원을 요청하시겠습니까?\n(데이터 양에 따라 시간이 오래 걸릴 수 있습니다.)")) {
233	            let data = {
234	                "cFrmDate": $("#cFrmDate").val(),
235	                "cToDate": $("#cToDate").val(),
236	                "sttemntNo": $("#sttemntNoSrchHead").val() + "-" + $("#sttemntNoSrchBody").val()
237	            };
238	            $.ajax({
239	                url: "<c:url value='/fileRestore/updateAllFileRestore.do'/>",
240	                type: 'post',
241	                data: data,
242	                dataType: 'json',
243	                success: function(res) {
244	                    alert(res.message);
245	                    ajaxData(nowPage);
246	                },
247	                error: function() {
248	                    alert("서버 통신 중 오류가 발생했습니다.");
249	                }
250	            });
251	        }
252	    }
253	
254	    function sethyphen(obj) {
255	        let rawVal = obj.value.replace(/-/g, '');
256	        if (rawVal.length > 4) obj.value = rawVal.slice(0, 4) + '-' + rawVal.slice(4);
257	        else obj.value = rawVal;
258	    }
259	
260	    function fnRowClick() {
261	        if (datagrid.getMouseRow() === 0 || datagrid.getCol() === 0 || datagrid.getCol() === 1) {
262	            return false;
263	        }
264	        const cNo = datagrid.getTextMatrix(datagrid.getMouseRow(), datagrid.getColRef("cNo"));
265	        const sttemntNo = datagrid.getTextMatrix(datagrid.getMouseRow(), datagrid.getColRef("sttemntNo"));
266	        const param = {
267	            "C_NO" : cNo,
268	            "STTEMNT_NO" : sttemntNo,
269	            "TITLE": "신고현황"
270	        };
271	        const url = "/sia/vhclTrfcVltnInq/safeSingoMngInqPup.do?menuId="+"<c:out value='${param.menuId}'/>";
272	        fn_postUrlPopupSingle(url, "1500", "800", param);
273	    }
274	</script>
275	</body>
276	</html>
