31	@Controller
32	@RequestMapping(value = "/fileRestore")
33	public class FileRestoreMngController extends KwebException {
34	    private static final Logger logger = LoggerFactory.getLogger(FileRestoreMngController.class);
35	
36	    @Autowired
37	    private CommonUtil commonUtl;
38	
39	    @Resource(name = "fileRestoreMngService")
40	    private FileRestoreMngService fileRestoreMngService;
41	
42	    /**
43	     * 파일 복원 관리 화면 호출
44	     */
45	    @RequestMapping(value = "/fileRestoreMng.do")
46	    public ModelAndView fileRestoreMng(FileSyncMngDto dto) throws Exception {
47	        String url = "sia/web/fileSync/fileRestoreMng";
48	
49	        Date d = new Date();
50	        Date fromDate = DateUtils.addDays(d, -7); // 기본 1주일
51	        Date toDate = DateUtils.addDays(d, -3); // 최대 3일
52	        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd");
53	
54	        if (StringUtils.isBlank(dto.getcFrmDate())) {
55	            dto.setcFrmDate(sdf.format(fromDate));
56	        }
57	        if (StringUtils.isBlank(dto.getcToDate())) {
58	            dto.setcToDate(sdf.format(toDate));
59	        }
60	
61	        mv.addObject("prePram", dto);
62	        return success(url);
63	    }
64	
65	    /**
66	     * 파일 복원 대상 목록 조회
67	     */
68	    @RequestMapping(value = "/selectRestoreSingoList.json")
69	    public ModelAndView selectRestoreSingoList(FileSyncMngDto dto, Model model) throws Exception {
70	        HashMap<String, Object> commandMap = new HashMap<>();
71	        if (dto.getNewPage() > 0) {
72	            commandMap.put("newPage", dto.getNewPage());
73	        }
74	
75	        commandMap.put("viewPageCnt", 20);
76	        commonUtl.pageSetting(commandMap);
77	
78	        dto.setStartRowNum(MapUtils.getInteger(commandMap, "startRowNum"));
79	        dto.setEndRowNum(MapUtils.getInteger(commandMap, "endRowNum"));
80	        dto.setNewPage(MapUtils.getInteger(commandMap, "newPage"));
81	        dto.setPageSize(MapUtils.getInteger(commandMap, "pageSize"));
82	
83	        List<FileSyncMngVO> resultList = fileRestoreMngService.selectRestoreSingoList(dto);
84	        int resultCnt = fileRestoreMngService.selectRestoreSingoListCnt(dto);
85	        int totalFileCnt = fileRestoreMngService.selectRestoreSingoFileTotalCnt(dto);
86	
87	        mv.addObject("param", dto);
88	        mv.addObject("resultList", resultList);
89	        mv.addObject("maxPage", resultCnt);
90	        mv.addObject("newPage", dto.getNewPage());
91	        mv.addObject("pageSize", dto.getPageSize());
92	        mv.addObject("totalFileCnt", totalFileCnt);
93	
94	        return success();
95	    }
96	
97	    /**
98	     * 일괄 파일 복원 처리
99	     */
100	    @RequestMapping(value = "/updateBulkFileRestore.do")
101	    @ResponseBody
102	    public Map<String, Object> updateBulkFileRestore(@RequestParam(value = "singoNos[]") List<Integer> singoNos, HttpServletRequest request) throws Exception {
103	        HttpSession session = request.getSession();
104	        String userId = (String) session.getAttribute("userId");
105	
106	        try {
107	            return fileRestoreMngService.updateBulkFileRestore(singoNos, userId);
108	        } catch (Exception e) {
109	            Map<String, Object> errorMap = new HashMap<>();
110	            errorMap.put("success", false);
111	            errorMap.put("message", "처리 중 오류가 발생했습니다: " + e.getMessage());
112	            return errorMap;
113	        }
114	    }
115	
116	    /**
117	     * 조회 결과 전체 파일 복원 처리
118	     */
119	    @RequestMapping(value = "/updateAllFileRestore.do")
120	    @ResponseBody
121	    public Map<String, Object> updateAllFileRestore(FileSyncMngDto dto, HttpServletRequest request) throws Exception {
122	        HttpSession session = request.getSession();
123	        String userId = (String) session.getAttribute("userId");
124	
125	        try {
126	            return fileRestoreMngService.updateAllFileRestore(dto, userId);
127	        } catch (Exception e) {
128	            Map<String, Object> errorMap = new HashMap<>();
129	            errorMap.put("success", false);
130	            errorMap.put("message", "처리 중 오류가 발생했습니다: " + e.getMessage());
131	            return errorMap;
132	        }
133	    }
134	}
