41	    @Override
42	    public Map<String, Object> updateBulkFileRestore(List<Integer> singoNos, String userId) throws Exception {
43	        Map<String, Object> resultMap = new HashMap<>();
44	        List<String> messages = Collections.synchronizedList(new ArrayList<>());
45	
46	        long successCnt = singoNos.stream()
47	            .map(singoNo -> {
48	                HashMap<String, Object> paramMap = new HashMap<>();
49	                paramMap.put("C_NO", singoNo);
